#include<bits/stdc++.h>
using namespace std;
int a[1000005];
int main()
{
	int n;
	cin>>n;
	for(int i=1;i<=n;i++)cin>>a[i];
	sort(a+1,a+n+1);
	int cnt=1,flag=0;
	for(int i=1;i<=n;i++){
		if(cnt<=a[i]){
			flag=1;
			cnt++;
		//	cout<<cnt<<" ";
		}
	}
	if(!flag)cout<<0;
	else cout<<cnt-1; 
}
